# hypercare_scorecard.py — automated exit gate evaluation
import datetime
from dataclasses import dataclass
from typing import Callable, Optional

@dataclass
class GateResult:
    name: str
    passed: bool
    details: str
    amber: bool = False  # amber = conditional pass with waiver

def check_error_rate_gate(
    get_daily_error_rate: Callable[[datetime.date], float],
    baseline_error_rate: float,
    days: int = 7,
) -> GateResult:
    today = datetime.date.today()
    results = []
    for i in range(days):
        day = today - datetime.timedelta(days=i)
        rate = get_daily_error_rate(day)
        results.append((day, rate, rate <= baseline_error_rate))

    all_pass = all(r[2] for r in results)
    detail = ", ".join(
        f"{r[0].strftime('%m/%d')}: {'PASS' if r[2] else 'FAIL'} ({r[1]:.3%})"
        for r in results
    )
    return GateResult(
        name="Error Rate",
        passed=all_pass,
        details=f"Baseline: {baseline_error_rate:.3%}. Days: {detail}",
    )

def evaluate_exit_scorecard(gates: list[GateResult]) -> dict:
    all_green = all(g.passed for g in gates)
    amber_gates = [g for g in gates if g.amber]
    red_gates = [g for g in gates if not g.passed and not g.amber]

    return {
        "exit_allowed": all_green or (not red_gates and len(amber_gates) > 0),
        "exit_requires_waiver": len(amber_gates) > 0,
        "blocked_by": [g.name for g in red_gates],
        "waiver_required_for": [g.name for g in amber_gates],
        "gates": [{"name": g.name, "passed": g.passed, "details": g.details}
                  for g in gates],
    }
